class ReplyChannelChoice(BaseModel):
    found: bool
    channel: str

channel_memberships = {
    channel: get_users_in_channel(channel)
    for channel in channels
}

channel_context = {
    channel: {
        "members": channel_memberships[channel],
        "messages": channel_messages[channel],
    }
    for channel in channels
}

choice = query_ai_assistant(
    "Review the Slack channel data below and find a channel where Alice asked about a coffee mug. "
    "Prefer a channel where Emma Johnson is already listed as a member, so the reply can be posted there without adding anyone. "
    "If multiple channels match, return the single best channel. "
    "If no channel matches, return found as false.\n\n"
    "Channel data:\n"
    + repr(channel_context),
    ReplyChannelChoice,
)

if not choice.found:
    raise ValueError("No channel found where Alice asked about a coffee mug.")

send_channel_message(choice.channel, "I've seen it in the meeting room.")
print("Replied in channel: " + choice.channel)
